-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Ghi đè vị trí ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Phím lưu nhanh ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Vị trí tùy chỉnh: TẮT " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Đã lưu: không có " })

SpotLeft:AddButton("Lưu vị trí hiện tại ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Lỗi ", Description="Không có nhân vật! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Lỗi ", Description="Không có HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Đã lưu vị trí! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Xóa vị trí tùy chỉnh ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Đã lưu: không có ")
    Library:Notify({Title="Đã xóa ", Description="Đang dùng vị trí đã ghi nhận ban đầu. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

